inline const TemplateCrops* lookup_template(int tcg_id, int template_id) {
    if (template_id < 0) return nullptr;
    if (tcg_id == 0) {
        if ((size_t)template_id >= k_n_templates_mtg) return nullptr;
        return &k_templates_mtg[template_id];
    }
    if (tcg_id == 1) {
        if ((size_t)template_id >= k_n_templates_pokemon) return nullptr;
        return &k_templates_pokemon[template_id];
    }
    if (tcg_id == 2) {
        if ((size_t)template_id >= k_n_templates_yugioh) return nullptr;
        return &k_templates_yugioh[template_id];
    }
    return nullptr;
}
